function output = fClcEngeV01(z,coeff,argF)%% output = fClcEngeV01(z,coeff,argF)% calculate enge function F = Enge(z,coeff)% % Output is output F%% Input% z: % coeff: Enge coefficient% argF(1): gap% argF(2): order of Enge function%% Function Calculate enge function ver.1% Written by Kei Nakamura%% Ver.1: 2012/11/15, Thursday% Created.%%% bodyexpnt = coeff(1);     % exponents, inside of expfor kk=1:argF(2)    expnt = expnt + coeff(kk+1).*(z/argF(1)).^kk;endoutput = 1./(1+exp(expnt));  % B fit result
